/**
 * BreadthStockModal.js
 *
 * Drill-down stock list modal for the Stockbee Market Monitor.
 * Reads from /breadth_stocks_{filter}.json (pre-generated by breadth_stocks_builder.py).
 *
 * Two views:
 *   List    — flat table: #, Ticker, Company, $Vol, ADR%, Change%
 *   Group   — grouped by industry with copy-ticker buttons
 */

import { memo, useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Check, Clipboard, ClipboardCheck, Copy, ExternalLink, Layers, LayoutList, Loader2, X } from "lucide-react";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function fmtPct(v) {
  if (v == null) return "—";
  const s = Math.abs(v).toFixed(2);
  return v > 0 ? `+${s}%` : `-${s}%`;
}

function fmtPrice(v) {
  if (v == null) return "—";
  return `$${v.toFixed(2)}`;
}

function changeCls(v) {
  if (v == null) return "text-zinc-500";
  return v > 0 ? "text-emerald-400" : "text-rose-400";
}

// ---------------------------------------------------------------------------
// Copy button
// ---------------------------------------------------------------------------

const CopyButton = memo(function CopyButton({ tickers, label }) {
  const [copied, setCopied] = useState(false);
  const timer = useRef(null);

  const handleCopy = useCallback((e) => {
    e.stopPropagation();
    navigator.clipboard.writeText(tickers.join(",")).then(() => {
      setCopied(true);
      clearTimeout(timer.current);
      timer.current = setTimeout(() => setCopied(false), 1800);
    });
  }, [tickers]);

  useEffect(() => () => clearTimeout(timer.current), []);

  return (
    <button
      onClick={handleCopy}
      title={`Copy ${tickers.length} tickers`}
      className={`inline-flex items-center gap-1 rounded px-2 py-0.5 text-xs transition-colors
        hover:bg-zinc-700 ${copied ? "text-emerald-400" : "text-zinc-500 hover:text-zinc-300"}`}
    >
      {copied ? <Check className="h-3 w-3" /> : <Copy className="h-3 w-3" />}
      <span>{copied ? "Copied" : (label ?? tickers.length)}</span>
    </button>
  );
});

// "Add to Clipboard" button — shown in the modal header, adds tickers to the
// persistent WatchlistClipboard in MarketBreadthMonitor.
const AddToClipboardButton = memo(function AddToClipboardButton({ label, tickers, filter, onAdd }) {
  const [added, setAdded] = useState(false);
  const timer = useRef(null);

  const handleClick = useCallback(() => {
    onAdd(label, tickers, filter);
    setAdded(true);
    clearTimeout(timer.current);
    timer.current = setTimeout(() => setAdded(false), 1800);
  }, [label, tickers, filter, onAdd]);

  useEffect(() => () => clearTimeout(timer.current), []);

  return (
    <button
      onClick={handleClick}
      className={`inline-flex items-center gap-1.5 rounded px-2.5 py-1 text-xs transition-colors
        ${added
          ? "bg-emerald-600/20 text-emerald-400 border border-emerald-600/40"
          : "bg-zinc-800 text-zinc-300 hover:bg-zinc-700 hover:text-zinc-100 border border-zinc-700"
        }`}
    >
      {added ? <ClipboardCheck className="h-3.5 w-3.5" /> : <Clipboard className="h-3.5 w-3.5" />}
      {added ? "Added!" : "Add to Clipboard"}
    </button>
  );
});

